import json
import re

papers_file = locals()['var_function-call-6614480246128303859']
with open(papers_file, 'r') as f:
    papers_data = json.load(f)

chi_filenames = []
pattern = r"(?:^|[^A-Za-z0-9])CHI(?:$|[^A-Za-z0-9])"

for p in papers_data:
    text = p['text']
    fname = p['filename']

    header = text[:1000]
    footer = text[-1000:]
    combined = header + " " + footer

    match = re.search(pattern, combined)

    if match:
        if re.search(r"Ubicomp", combined, re.IGNORECASE):
            if re.search(pattern, header):
                chi_filenames.append(fname)
            else:
                if re.search(r"Ubicomp", header, re.IGNORECASE):
                    pass
                else:
                    if re.search(r"CHI\s*.?\s*\d{2}", footer):
                        chi_filenames.append(fname)
        else:
            chi_filenames.append(fname)

citations_file = locals()['var_function-call-10006919701169471588']
with open(citations_file, 'r') as f:
    citations_data = json.load(f)

chi_titles = set(f.replace('.txt', '') for f in chi_filenames)

details = []
total = 0
for c in citations_data:
    if c['title'] in chi_titles:
        details.append({
            "title": c['title'], 
            "count": c['citation_count']
        })
        total += int(c['citation_count'])

print("__RESULT__:")
print(json.dumps({"total": total, "details": details}))

